WHERE p.is_active = 1

      AND (p.hospital_id = #{hospitalId} OR p.hospital_id IS NULL)


      AND p.enabled = #{filter.enabled}


      AND p.dicom_server_id = #{filter.dicomServerId}


      AND p.modality_id = #{filter.modalityId}


      AND (
          COALESCE(h.name, '') ILIKE '%' || #{filter.searchText} || '%'
          OR COALESCE(ds.name, '') ILIKE '%' || #{filter.searchText} || '%'
          OR COALESCE(m.abbr, '') ILIKE '%' || #{filter.searchText} || '%'
          OR COALESCE(m.name, '') ILIKE '%' || #{filter.searchText} || '%'
          OR COALESCE(p.notes, '') ILIKE '%' || #{filter.searchText} || '%'
      )

mapper.select:
SELECT
ORDER BY CASE WHEN p.hospital_id IS NULL THEN 1 ELSE 0 END, COALESCE(h.name, ''), COALESCE(ds.name, ''), COALESCE(m.abbr, m.name, ''), p.modified_at DESC, p.id DESC
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}

SELECT


WHERE p.id = #{id}
  AND p.is_active = 1

      AND p.hospital_id = #{hospitalId}

LIMIT 1

SELECT COUNT(1)
FROM hospital_dicom_servers
WHERE id = #{dicomServerId}
  AND hospital_id = #{hospitalId}
  AND is_active != 2

mapper.sql:
SELECT candidate.*, CASE WHEN candidate.latestDecisionStatus = 'DELETE_FAILED' THEN 'DELETE_FAILED' WHEN candidate.latestDecisionStatus = 'KEEP_PERMANENT' THEN 'KEEP_PERMANENT' WHEN candidate.latestDecisionStatus = 'REJECTED' THEN 'REJECTED' WHEN candidate.latestDecisionStatus IN ('PENDING_APPROVAL', 'APPROVED') THEN 'PENDING_APPROVAL' WHEN candidate.latestDecisionStatus = 'DELETED' THEN 'DELETED' WHEN candidate.expires_at_value <= NOW() THEN 'EXPIRED_WAITING_APPROVAL' WHEN candidate.near_expiry_at_value <= NOW() THEN 'NEAR_EXPIRY' ELSE 'ACTIVE' END AS status, CEIL(EXTRACT(EPOCH FROM (candidate.expires_at_value - NOW())) / 86400.0)::BIGINT AS daysUntilExpiry FROM ( SELECT s.id AS studyId, s.public_id::text AS studyPublicKey, s.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.name AS hospitalName, policy.id AS policyId, policy.public_id::text AS policyPublicKey, s.dicom_server_id AS dicomServerId, ds.public_id::text AS dicomServerPublicKey, ds.name AS dicomServerName, study_modality.id AS modalityId, study_modality.public_id::text AS modalityPublicKey, COALESCE(NULLIF(study_modality.abbr, ''), s.modality) AS modalityCode, study_modality.name AS modalityName, NULLIF(TRIM(CONCAT(COALESCE(patient.first_name, ''), ' ', COALESCE(patient.last_name, ''))), '') AS patientName, patient.patient_uid AS patientMrn, s.accession_number AS accessionNumber, s.reference_visit_code AS referenceVisitCode, s.study_instance_uid AS studyInstanceUid, s.dicom_server_study_id AS dicomServerStudyId, TO_CHAR(s.study_date, 'YYYY-MM-DD') AS studyDate, TO_CHAR(COALESCE(s.image_received_at, s.received_at), 'YYYY-MM-DD HH24:MI:SS') AS imageReceivedAt, policy.retention_days AS retentionDays, policy.notify_before_days AS notifyBeforeDays, TO_CHAR(base_dates.retention_base_at, 'YYYY-MM-DD HH24:MI:SS') AS retentionBaseAt, TO_CHAR(base_dates.retention_base_at + (policy.retention_days * INTERVAL '1 day') - (policy.notify_before_days * INTERVAL '1 day'), 'YYYY-MM-DD HH24:MI:SS') AS nearExpiryAt, TO_CHAR(base_dates.retention_base_at + (policy.retention_days * INTERVAL '1 day'), 'YYYY-MM-DD HH24:MI:SS') AS expiresAt, base_dates.retention_base_at + (policy.notify_before_days * INTERVAL '0 day') AS retention_base_value, base_dates.retention_base_at + (policy.retention_days * INTERVAL '1 day') - (policy.notify_before_days * INTERVAL '1 day') AS near_expiry_at_value, base_dates.retention_base_at + (policy.retention_days * INTERVAL '1 day') AS expires_at_value, latest.status AS latestDecisionStatus, latest.decision_note AS decisionNote, latest.error_message AS errorMessage, TO_CHAR(latest.requested_at, 'YYYY-MM-DD HH24:MI:SS') AS requestedAt, TO_CHAR(latest.approved_at, 'YYYY-MM-DD HH24:MI:SS') AS approvedAt, TO_CHAR(latest.rejected_at, 'YYYY-MM-DD HH24:MI:SS') AS rejectedAt, TO_CHAR(latest.deleted_at, 'YYYY-MM-DD HH24:MI:SS') AS deletedAt FROM pacs_studies s INNER JOIN hospitals h ON h.id = s.hospital_id INNER JOIN patients patient ON patient.id = s.patient_id AND patient.hospital_id = s.hospital_id LEFT JOIN hospital_dicom_servers ds ON ds.id = s.dicom_server_id LEFT JOIN LATERAL ( SELECT m.* FROM modalities m WHERE m.is_active = 1 AND ( m.id = s.modality_id OR ( s.modality_id IS NULL AND ( UPPER(COALESCE(m.abbr, '')) = UPPER(COALESCE(s.modality, '')) OR UPPER(COALESCE(m.name, '')) = UPPER(COALESCE(s.modality, '')) ) ) ) ORDER BY CASE WHEN m.id = s.modality_id THEN 0 ELSE 1 END, m.id ASC LIMIT 1 ) study_modality ON TRUE CROSS JOIN LATERAL ( SELECT COALESCE( s.image_received_at, s.received_at, s.study_date::timestamp AT TIME ZONE 'UTC', s.created, NOW() ) AS retention_base_at ) base_dates INNER JOIN LATERAL ( SELECT p.* FROM study_retention_policies p WHERE p.is_active = 1 AND p.enabled = TRUE AND (p.hospital_id IS NULL OR p.hospital_id = s.hospital_id) AND (p.dicom_server_id IS NULL OR p.dicom_server_id = s.dicom_server_id) AND (p.modality_id IS NULL OR p.modality_id = study_modality.id) ORDER BY CASE WHEN p.hospital_id IS NULL THEN 0 ELSE 1 END DESC, CASE WHEN p.dicom_server_id IS NULL THEN 0 ELSE 1 END DESC, CASE WHEN p.modality_id IS NULL THEN 0 ELSE 1 END DESC, p.modified_at DESC, p.id DESC LIMIT 1 ) policy ON TRUE LEFT JOIN LATERAL ( SELECT request.* FROM study_retention_delete_requests request WHERE request.hospital_id = s.hospital_id AND request.study_id = s.id ORDER BY request.created_at DESC, request.id DESC LIMIT 1 ) latest ON TRUE WHERE s.is_active = 1
AND s.hospital_id = #{hospitalId}
) candidate

mapper.select:
WITH retention_rows AS (
) SELECT * FROM retention_rows WHERE status != 'DELETED'
ORDER BY CASE status WHEN 'DELETE_FAILED' THEN 0 WHEN 'EXPIRED_WAITING_APPROVAL' THEN 1 WHEN 'PENDING_APPROVAL' THEN 2 WHEN 'NEAR_EXPIRY' THEN 3 WHEN 'REJECTED' THEN 4 WHEN 'KEEP_PERMANENT' THEN 5 ELSE 6 END, expires_at_value ASC, studyId DESC
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}

WITH target_worklists AS (
    SELECT DISTINCT q.id
    FROM pacs_worklists q
    WHERE q.hospital_id = #{hospitalId}
      AND (
          q.study_id = #{studyId}
          OR EXISTS (
              SELECT 1
              FROM pacs_worklist_study_links link
              WHERE link.hospital_id = q.hospital_id
                AND link.worklist_id = q.id
                AND link.study_id = #{studyId}
          )
      )
),
deleted_viewer_states AS (
    DELETE FROM pacs_viewer_states vs
    WHERE vs.hospital_id = #{hospitalId}
      AND (
          vs.study_id = #{studyId}
          OR EXISTS (SELECT 1 FROM target_worklists tw WHERE tw.id = vs.worklist_id)
      )
    RETURNING 1
),
deleted_results AS (
    DELETE FROM pacs_results pr
    WHERE pr.hospital_id = #{hospitalId}
      AND (
          pr.study_id = #{studyId}
          OR EXISTS (SELECT 1 FROM target_worklists tw WHERE tw.id = pr.worklist_id)
      )
    RETURNING 1
),
deleted_worklist_links AS (
    DELETE FROM pacs_worklist_study_links link
    WHERE link.hospital_id = #{hospitalId}
      AND (
          link.study_id = #{studyId}
          OR EXISTS (SELECT 1 FROM target_worklists tw WHERE tw.id = link.worklist_id)
      )
    RETURNING 1
),
deleted_worklist_histories AS (
    DELETE FROM pacs_worklist_histories history
    WHERE history.hospital_id = #{hospitalId}
      AND EXISTS (SELECT 1 FROM target_worklists tw WHERE tw.id = history.worklist_id)
    RETURNING 1
),
deleted_worklists AS (
    DELETE FROM pacs_worklists q
    WHERE q.hospital_id = #{hospitalId}
      AND EXISTS (SELECT 1 FROM target_worklists tw WHERE tw.id = q.id)
    RETURNING 1
),
deleted_study AS (
    DELETE FROM pacs_studies s
    WHERE s.hospital_id = #{hospitalId}
      AND s.id = #{studyId}
    RETURNING 1
)
SELECT COALESCE((SELECT COUNT(1) FROM deleted_study), 0)::INTEGER
